VALUES
  ('elementary-d0d1b9a2-moex-00865', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '「預付租金」項目期初餘額為$80,000，期末餘額為$50,000，另本期為租金共支付現金$130,000，則本期 綜合損益表上之租金費用應為：', '["$100,000", "$160,000", "$140,000", "$260,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00866', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司購入乙公司30%的普通股故具重大影響力。試問下列敘述何者錯誤？', '["甲公司對該投資應採權益法進行相關之帳務處理", "甲公司應以乙公司股票之公允價值調整投資之帳面金額", "甲公司應就乙公司之當年損益，依持股比例認列投資損益", "若乙公司支付現金股利，則甲公司應認列投資減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00867', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列何者係認列於本期其他綜合損益項下？', '["透過其他綜合損益按公允價值衡量之債務工具投資未實現評價損益", "停業單位損益", "預期信用減損損失", "所得稅費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00868', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司存貨會計記錄採用永續盤存制及先進先出法，下列為甲公司X1年度相關資訊（依據時間發生之先 後順序）： 單位數 單位成本 期初存貨 10 $20 進貨 40 22 進貨 20 21 銷貨（每單位售價$35） 50 進貨 60 25 銷貨（每單位售價$35） 30 若甲公司期末存貨之淨變現價值為$1,200，請問甲公司X1年之銷貨成本金額為何？', '["$1,750", "$1,800", "$1,830", "$1,860"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00869', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司於X1年10月1日以每股$50買入乙公司股票3,000股，並將此投資透過損益按公允價值衡量，乙 公司股票於X1年年底的每股市價為$43。甲公司於X2年7月1日收到乙公司所發放的現金股利$2,400， 且於X2年8月15日以每股$59出售所有乙公司股票。請問甲公司該投資對X2年淨利之影響為何？', '["$29,400", "$27,000", "$50,400", "$48,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00870', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '會計期間終了時：', '["無論存貨採用定期盤存制或永續盤存制，都需進行實地盤點", "若存貨採用定期盤存制，則需進行實地盤點；若採用永續盤存制，則不用實地盤點", "若存貨採用永續盤存制，則需進行實地盤點；若採用定期盤存制，則不用實地盤點", "無論存貨採用定期盤存制或永續盤存制，都不需進行實地盤點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00871', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲車行提供載客交通服務，則其營運用的計程車是甲車行之：', '["存貨", "投資性不動產", "不動產、廠房及設備", "流動資產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00872', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '企業對不動產、廠房及設備會計政策採重估價模式。若公允價值與原帳面金額發生重大差異而首次進行 重估價，應如何處理？', '["不論重估增值或減值，兩者之差額均列入本期損益", "不論重估增值或減值，兩者之差額均列入其他綜合損益", "發生重估增值，增加數列為本期損益；發生重估減值，減少數列入其他綜合損益", "發生重估增值，增加數列為其他綜合損益；發生重估減值，減少數列入本期損益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00873', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '丙公司X2年6月1日以$630,000購入一套影音設備，估計耐用年限8年，殘值$30,000，以直線法提列 折舊。X5年1月1日丙公司改以雙倍餘額遞減法提列折舊，且估計耐用年限尚有4年，殘值不變。下列 敘述何者正確？', '["X2年底設備帳面金額$592,500", "X4年底設備帳面金額$435,000", "X5年度折舊$218,125", "X6年度折舊$108,125"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00874', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-110-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '購入房地產乙棟，總價$10,800,000，土地的公允價值為$8,000,000，房屋的公允價值為$4,000,000；則土 地與房屋帳上原始認列金額為：', '["土地$8,000,000，房屋$2,800,000", "土地$6,800,000，房屋$4,000,000", "土地$7,200,000，房屋$3,600,000", "土地$8,000,000，房屋$4,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:49+00:00", "source_pdf_sha1": "a85a4ce0d905", "answer_pdf_sha1": "9efeab6ae8d5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "509", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
